VALUES
  ('real-estate-moex-01064', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將房屋出賣於乙並交付之，但尚未完成移轉登記，乙已支付一半價金，其後該屋因地震而全毀。下列 敘述，何者正確？', '["乙仍應支付全部買賣價金", "甲應承擔一半損失", "乙得解除買賣契約", "甲得主張重建後再交屋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01065', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於代理，下列敘述何者正確？', '["代理人非經本人之許諾，不得既為第三人之代理人，而為本人與第三人之法律行為。但其法律行為， 係專履行債務者，不在此限", "代理權之限制及撤回，不得以之對抗善意第三人。至於該第三人有無過失而不知其事實者，則非所問", "代理人於代理權限內，以代理人名義所為之意思表示，直接對本人發生效力", "代理人所為或所受意思表示之效力，不因其為無行為能力人而受影響"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01066', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲駕駛機車載乙，與丙發生車禍，致乙跌落機車，身體多處受傷，經查甲、丙均有過失。下列敘述，何 者錯誤？', '["乙得向丙請求損害賠償", "丙不得主張乙應承擔甲之過失", "乙得向甲請求損害賠償", "甲丙為共同侵權行為人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01067', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於共有物分割，下列敘述何者正確？', '["共有物依共有人協議分割時，並不適用多數決原則", "共有人以契約訂有不分割之期限者不得逾十年；逾十年者，縮短為十年", "共有之不動產，其契約訂有管理之約定時，約定不分割之期限，不得逾五十年；逾五十年者，縮短為 五十年", "不動產共有人間關於共有物分割或禁止分割之約定，對於應有部分之受讓人或取得物權之人，以受讓 或取得時知悉其情事或可得而知者為限，亦具有效力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01068', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於居間人之報酬及支出費用，下列敘述何者正確？', '["契約附有解除條件者，於該條件成就前，居間人不得請求報酬", "居間人因媒介應得之報酬，除契約另有訂定或另有習慣外，應由契約當事人雙方平均負擔", "約定之報酬，較居間人所任勞務之價值，為數過鉅失其公平者，報酬給付義務人得以意思表示請求酌減之", "居間人違反其對於委託人之義務，而為利於委託人之相對人之行為，或違反誠實及信用方法，由相對 人收受利益者，不得向委託人請求報酬，僅得請求償還其支出之必要費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01069', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙係多年好友，甲長年於國外經商，遂概括委任乙代為管理A屋，約定乙就A屋得為甲為一切行為。 但民法規定，不動產之租賃其期限逾多久者，乙仍須有特別授權？', '["二年", "一年半", "一年", "半年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01070', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於合夥人出資及合夥財產，下列敘述何者正確？', '["合夥人之出資，得為金錢，其他財產權或勞務，但不得以信用代之", "合夥財產不足清償合夥之債務時，各合夥人對於不足之額，連帶負其責任", "合夥人之出資及其他合夥財產，為合夥人全體分別共有之集合財產", "合夥因損失而至資本減少時，除合夥契約有特別訂定外，合夥人有補充之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01071', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲自行出資建造違章建築房屋一幢，將之出售予乙，並已交付乙占有。但事後甲對乙主張其為所有權人， 請求乙返還房屋。下列敘述何者正確？', '["甲之請求為無理由。因為違章建築是違法行為，甲無法取得該屋所有權", "甲之請求為有理由。因為違章建築買賣是違法行為，買賣契約無效，甲得請求回復原狀", "甲之請求為有理由。甲可根據民法第767條第1項前段，所有人對於無權占有或侵奪其所有物者，得 請求返還之", "甲之請求為無理由。縱甲根據民法第767條第1項前段，所有人對於無權占有或侵奪其所有物者，得 請求返還之。乙基於買賣契約非無權占有該屋，故無須返還"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01072', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙、丙共同竊取丁之財物，丁損失共計新臺幣30萬元，丁僅原諒其子甲之行為，而免除其債務。下 列敘述，何者正確？', '["乙若全額清償後，得向甲、丙各求償新臺幣10萬元", "乙若全額清償後，僅得向丙求償新臺幣10萬元", "乙若全額清償後，僅得向丙求償新臺幣15萬元", "丁免除甲之債務，乙、丙之債務亦應同生免除效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01073', 'real-estate', 'real-estate-moex-103-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於越界建築之處理，下列敘述何者正確？', '["土地所有人建築圍牆時因重大過失逾越地界者，鄰地所有人如知其越界而不即提出異議，不得請求移 去或變更其圍牆", "土地所有人建築圍牆時非因重大過失逾越地界者，鄰地所有人如知其越界而不即提出異議，不得請求 移去或變更其圍牆", "土地所有人建築房屋時因重大過失逾越地界者，鄰地所有人如知其越界而不即提出異議，不得請求移 去或變更其房屋", "土地所有人建築房屋時非因重大過失逾越地界者，鄰地所有人如知其越界而不即提出異議，不得請求 移去或變更其房屋"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "0f1a30d7e20e", "answer_pdf_sha1": "b08d70edc4f5", "source_family": "moex-gov-tw", "moex": {"exam_code": "103170", "c": "601", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "103", "exam_name": "103年專門建築師技師第二次食品技師考試不動產經紀人記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
